glsl3.vert:
precision highp float;
layout(std140) uniform CCGlobal {
  highp   vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_nativeSize;
  mediump vec4 cc_probeInfo;
  mediump vec4 cc_debug_view_mode;
};
layout(std140) uniform CCCamera {
  highp   mat4 cc_matView;
  highp   mat4 cc_matViewInv;
  highp   mat4 cc_matProj;
  highp   mat4 cc_matProjInv;
  highp   mat4 cc_matViewProj;
  highp   mat4 cc_matViewProjInv;
  highp   vec4 cc_cameraPos;
  mediump vec4 cc_surfaceTransform;
  mediump vec4 cc_screenScale;
  mediump vec4 cc_exposure;
  mediump vec4 cc_mainLitDir;
  mediump vec4 cc_mainLitColor;
  mediump vec4 cc_ambientSky;
  mediump vec4 cc_ambientGround;
  mediump vec4 cc_fogColor;
  mediump vec4 cc_fogBase;
  mediump vec4 cc_fogAdd;
  mediump vec4 cc_nearFar;
  mediump vec4 cc_viewPort;
};
in vec3 a_position;
in vec2 a_texCoord;
in vec4 a_color;
layout(std140) uniform MyConstants {
  vec4 blurParams;
};
out vec4 v_color;
out vec2 v_uv;
out vec2 v_uv1;
out vec2 v_uv2;
out vec2 v_uv3;
out vec2 v_uv4;
vec4 vert () {
  vec4 pos = vec4(a_position, 1.0);
  pos = cc_matViewProj * pos;
  v_uv = a_texCoord;
  v_color = a_color;
  vec2 texelSize = cc_nativeSize.zw;
  float blurOffsetX = blurParams.x * texelSize.x;
  v_uv1 = v_uv + vec2(blurOffsetX * 1.0, 0.0);
  v_uv2 = v_uv - vec2(blurOffsetX * 1.0, 0.0);
  v_uv3 = v_uv + vec2(blurOffsetX * 2.0, 0.0);
  v_uv4 = v_uv - vec2(blurOffsetX * 2.0, 0.0);
  return pos;
}
void main() { gl_Position = vert(); }

glsl3.frag:
precision highp float;
#if USE_ALPHA_TEST
  layout(std140) uniform ALPHA_TEST_DATA {
    float alphaThreshold;
  };
#endif
void ALPHA_TEST (in vec4 color) {
  #if USE_ALPHA_TEST
    if (color.a < alphaThreshold) discard;
  #endif
}
void ALPHA_TEST (in float alpha) {
  #if USE_ALPHA_TEST
    if (alpha < alphaThreshold) discard;
  #endif
}
in vec4 v_color;
in vec2 v_uv;
in vec2 v_uv1;
in vec2 v_uv2;
in vec2 v_uv3;
in vec2 v_uv4;
#if USE_TEXTURE
uniform sampler2D mainTexture;
#endif
layout(location = 0) out vec4 fragColor;
void main () {
  vec4 o = vec4(1.0);
  vec3 weights = vec3(0.4026, 0.2442, 0.0545);
  #if USE_TEXTURE
  vec3 sum = texture(mainTexture, v_uv).rgb * weights.x;
  sum += texture(mainTexture, v_uv1).rgb * weights.y;
  sum += texture(mainTexture, v_uv2).rgb * weights.y;
  sum += texture(mainTexture, v_uv3).rgb * weights.z;
  sum += texture(mainTexture, v_uv4).rgb * weights.z;
  o = vec4(sum, texture(mainTexture, v_uv).a);
  #endif
  o *= v_color;
  ALPHA_TEST(o);
  fragColor = o;
}

